import unreal
walk = unreal.load_asset('/Game/Character/A_Walk')
skel = walk.get_skeleton() if hasattr(walk,'get_skeleton') else walk.get_editor_property('skeleton')
names = None
try:
    names = [str(n) for n in unreal.AnimPoseExtensions.get_bone_names(unreal.AnimPose())]
except Exception as e:
    print('pose ext direct err', e)
try:
    pose = unreal.AnimPoseExtensions.get_anim_pose_at_time(walk, 0.0)
    arr = unreal.Array(unreal.Name)
    unreal.AnimPoseExtensions.get_bone_names(pose, arr)
    names = [str(n) for n in arr]
except Exception as e:
    print('animpose err', e)
if names is None:
    try:
        pose = unreal.AnimPose()
        unreal.AnimPoseExtensions.evaluate_anim_pose(walk, unreal.AnimPoseEvaluationOptions(), 0.0, pose)
    except Exception as e:
        print('eval err', e)
print('NUM:', len(names) if names else 0)
print('BONES:', names)
